   348→    fn cache_key(tenant: Uuid, query: &ListQuery) -> String {
   349→        let filter = query.account_code.as_deref().unwrap_or("_");
   350→        let page = query.page.unwrap_or(1);
   351→        let per_page = query.per_page.unwrap_or(50);
   352→        format!("ledger_entries:{tenant}:{filter}:{page}:{per_page}")
   353→    }
   354→
   355→    #[instrument(skip(self))]
   356→    pub async fn list(
   357→        &self,
   358→        tenant: Uuid,
   359→        query: ListQuery,
   360→    ) -> Result<Paginated<LedgerEntryDto>, ServiceError> {
   361→        // 1. Try cache (30ms timeout to avoid head-of-line blocking)
   362→        let key = Self::cache_key(tenant, &query);
   363→        if let Ok(Some(raw)) = self.try_fetch_cache(&key).await {
   364→            debug!(%tenant, %key, "Cache hit");
   365→            return serde_json::from_slice::<Paginated<LedgerEntryDto>>(&raw)
   366→                .map_err(ServiceError::CacheSerialization);
   367→        }
   368→
   369→        // 2. Query repository
   370→        debug!(%tenant, "Cache miss – querying DB");
   371→        let (entries, total) = self.repo.list(tenant, &query).await?;
   372→        let dto: Vec<LedgerEntryDto> = entries.into_iter().map(Into::into).collect();
   373→
   374→        let page = query.page.unwrap_or(1);
   375→        let per_page = query.per_page.unwrap_or(50);
   376→        let total_pages = ((total as f64) / (per_page as f64)).ceil() as u32;
   377→
   378→        let payload = Paginated {
   379→            data: dto,
   380→            page,
   381→            per_page,
   382→            total_items: total,
   383→            total_pages,
   384→        };
   385→
   386→        // 3. Backfill cache (best-effort)
   387→        let _ = self.persist_cache(&key, &payload).await;
   388→
   389→        Ok(payload)
   390→    }
