   165→impl ResponseError for ApiError {
   166→    fn status_code(&self) -> StatusCode {
   167→        match self {
   168→            ApiError::Validation(_) => StatusCode::BAD_REQUEST,
   169→            ApiError::Unauthorized => StatusCode::UNAUTHORIZED,
   170→            ApiError::Internal(_) => StatusCode::INTERNAL_SERVER_ERROR,
   171→        }
   172→    }
   173→
   174→    fn error_response(&self) -> HttpResponse {
   175→        // Structured error envelope
   176→        #[derive(Serialize)]
   177→        struct ErrorBody<'a> {
   178→            error: &'a str,
   179→            message: String,
   180→        }
   181→
   182→        let body = match self {
   183→            ApiError::Validation(msg) => ErrorBody {
   184→                error: "validation_error",
   185→                message: msg.clone(),
   186→            },
   187→            ApiError::Unauthorized => ErrorBody {
   188→                error: "unauthorized",
   189→                message: "Authentication required".to_owned(),
   190→            },
   191→            ApiError::Internal(e) => {
   192→                // Hide internal details from the caller
   193→                error!(error = ?e, "internal server error");
   194→                ErrorBody {
   195→                    error: "internal_error",
   196→                    message: "An unexpected error occurred".to_owned(),
   197→                }
   198→            }
   199→        };
   200→
   201→        HttpResponse::build(self.status_code()).json(body)
   202→    }
   203→}
