   314→/// --------------------------------------------------------------------------------------------
   315→/// Endpoint handler
   316→/// --------------------------------------------------------------------------------------------
   317→#[get("/api/v1/ledger/entries")]
   318→#[instrument(skip(dto, state, auth), fields(tenant = %auth.tenant_id))]
   319→pub async fn get_ledger_entries(
   320→    auth: AuthContext,
   321→    Query(dto): Query<LedgerEntryQueryDto>,
   322→    state: Data<AppState>,
   323→) -> Result<Json<Paginated<LedgerEntry>>, ApiError> {
   324→    // Validate incoming DTO
   325→    dto.validate()
   326→        .map_err(|e| ApiError::Validation(e.to_string()))?;
   327→
   328→    let cache_key = make_cache_key(&auth.tenant_id, &dto);
   329→    debug!(%cache_key, "generated cache key");
   330→
   331→    // Attempt cache hit
   332→    let mut redis_conn = state
   333→        .redis
   334→        .get_async_connection()
   335→        .await
   336→        .map_err(|e| ApiError::Internal(e.into()))?;
   337→
   338→    if let Ok(cached) = redis_conn.get::<_, Vec<u8>>(cache_key.clone()).await {
   339→        if !cached.is_empty() {
   340→            debug!("cache hit");
   341→            let value: Paginated<LedgerEntry> =
   342→                serde_json::from_slice(&cached).map_err(|e| ApiError::Internal(e.into()))?;
   343→            return Ok(Json(value));
   344→        }
   345→    }
   346→
   347→    debug!("cache miss – fetching from service layer");
   348→
   349→    // Build domain filter/pagination structs
   350→    let filter = LedgerEntryFilter {
   351→        account_id: dto.account_id,
   352→        from_date: dto.from_date,
   353→        to_date: dto.to_date,
   354→    };
   355→    let pagination = Pagination {
   356→        page: dto.page,
   357→        per_page: dto.per_page,
   358→        sort_desc: dto.sort == "desc",
   359→    };
   360→
   361→    // Execute query
   362→    let result = state
   363→        .query_service
   364→        .query_entries(filter, pagination)
   365→        .await
   366→        .map_err(ApiError::Internal)?;
   367→
   368→    // Store in cache – set TTL 60s
   369→    let ttl_seconds = 60;
   370→    if let Ok(serialized) = serde_json::to_vec(&result) {
   371→        let _: () = redis_conn
   372→            .set_ex(cache_key, serialized, ttl_seconds)
   373→            .await
   374→            .unwrap_or_default();
   375→        debug!(ttl = ttl_seconds, "cached result");
   376→    }
   377→
   378→    info!(
   379→        page = result.page,
   380→        per_page = result.per_page,
   381→        total = result.total,
   382→        "ledger entries served"
   383→    );
   384→
   385→    Ok(Json(result))
   386→}
