id,\n    pub account_id: Uuid,\n    pub amount_minor: i64,\n    pub currency: String,\n    pub booked_at: DateTime<Utc>,\n    pub narrative: String,\n}\n\n/// --------------------------------------------------------------------------------------------\n/// Pagination envelope returned to clients\n/// --------------------------------------------------------------------------------------------\n#[derive(Debug, Serialize)]\npub struct Paginated<T> {\n    pub data: Vec<T>,\n    pub page: usize,\n    pub per_page: usize,\n    pub total: usize,\n}\n\n/// --------------------------------------------------------------------------------------------\n/// Cache key utilities\n/// --------------------------------------------------------------------------------------------\nfn make_cache_key(user_tenant: &str, dto: &LedgerEntryQueryDto) -> String {\n    // A simple but effective composite cache key\n    format!(\n        \"ledger_entries:v1:{}:{}:{}:{}:{}:{}:{}\",\n        user_tenant,\n        dto.page,\n        dto.per_page,\n        dto.account_id\n            .map(Uuid::to_string)\n            .unwrap_or_else(|| \"all\".into()),\n        dto.from_date\n            .map(|d| d.timestamp_millis().to_string())\n            .unwrap_or_else(|| \"min\".into()),\n        dto.to_date\n            .map(|d| d.timestamp_millis().to_string())\n            .unwrap_or_else(|| \"max\".into()),\n        dto.sort\n    )\n}\n\n/// --------------------------------------------------------------------------------------------\n/// Error handling\n/// --------------------------------------------------------------------------------------------\n#[derive(thiserror::Error, Debug)]\npub enum ApiError {\n    #[error(\"validation failed: {0}\")]\n    Validation(String),\n\n    #[error(\"unauthorized\")]\n    Unauthorized,\n\n    #[error(\"internal server error\")]\n    Internal(#[from] anyhow::Error),\n}\n\nimpl ResponseError for ApiError {\n    fn status_code(&self) -> StatusCode {\n        match self {