     2→//! LedgerLink Nexus – Pagination + Response Caching + Repository glue
     3→//! ------------------------------------------------------------------
     4→//! This module brings together three core cross-cutting concerns that are heavily
     5→//! reused throughout the micro-service:
     6→//!   1. Generic, typed pagination helpers with validation
     7→//!   2. A small opinionated Redis-backed response-caching façade
     8→//!   3. A sample Postgres repository implementation for Ledger Entries
     9→//!
    10→//! It is **self-contained** so it can be pulled into integration/unit tests
    11→//! without touching the rest of the codebase.
    12→
    13→#![allow(clippy::module_inception)] // we intentionally group sub-modules here
    14→#![deny(rust_2018_idioms)]
    15→
    16→use std::time::Duration;
    17→
    18→use async_trait::async_trait;
    19→use chrono::{DateTime, Utc};
    20→use futures::{future::BoxFuture, Future, FutureExt};
    21→use serde::{de::DeserializeOwned, Deserialize, Serialize};
    22→use sha2::{Digest, Sha256};
    23→use thiserror::Error;
    24→use tokio::{select, time::timeout};
    25→
    26→//
    27→// ─────────────────────────────  ERRORS  ────────────────────────────────
    28→//
    29→
    30→#[derive(Debug, Error)]
    31→pub enum ApiError {
    32→    #[error("validation error: {0}")]
    33→    Validation(String),
    34→
    35→    #[error("repository error: {0}")]
    36→    Repository(String),
    37→
    38→    #[error("cache error: {0}")]
    39→    Cache(String),
    40→
    41→    #[error("timeout after {0:?}")]
    42→    Timeout(Duration),
    43→
    44→    #[error(transparent)]
    45→    Other(#[from] anyhow::Error),
    46→}
