    48→//
    49→// ────────────────────────  PAGINATION PRIMITIVES  ──────────────────────
    50→//
    51→mod pagination {
    52→    use super::ApiError;
    53→    use serde::{Deserialize, Serialize};
    54→
    55→    /// Maximum number of items that can be requested in a single page
    56→    const MAX_PAGE_SIZE: u32 = 250;
    57→
    58→    /// Input query params coming from the client (View)
    59→    #[derive(Debug, Clone, Copy, Serialize, Deserialize)]
    60→    pub struct PageRequest {
    61→        pub page: u32,
    62→        pub size: u32,
    63→    }
    64→
    65→    impl Default for PageRequest {
    66→        fn default() -> Self {
    67→            Self { page: 1, size: 50 }
    68→        }
    69→    }
    70→
    71→    impl PageRequest {
    72→        /// Validates & bounds the request to ensure we never allocate unbounded
    73→        /// memory or inadvertently DoS ourselves.
    74→        pub fn validate(self) -> Result<Self, ApiError> {
    75→            if self.page == 0 {
    76→                return Err(ApiError::Validation("page index starts at 1".into()));
    77→            }
    78→            if self.size == 0 || self.size > MAX_PAGE_SIZE {
    79→                return Err(ApiError::Validation(format!(
    80→                    "size must be 1..={MAX_PAGE_SIZE}"
    81→                )));
    82→            }
    83→            Ok(self)
    84→        }
    85→
    86→        /// Calculates SQL `OFFSET`
    87→        pub fn offset(self) -> u32 {
    88→            (self.page.saturating_sub(1)) * self.size
    89→        }
    90→    }
    91→
    92→    /// Metadata returned alongside every paginated response
    93→    #[derive(Debug, Clone, Serialize, Deserialize)]
    94→    pub struct PageMeta {
    95→        pub page: u32,
    96→        pub size: u32,
    97→        pub total: u64,
    98→        pub has_next: bool,
    99→    }
   100→
   101→    /// Wrapper DTO sent over the wire
   102→    #[derive(Debug, Clone, Serialize, Deserialize)]
   103→    pub struct Paginated<T> {
   104→        pub data: Vec<T>,
   105→        pub meta: PageMeta,
   106→    }
   107→
   108→    impl<T> Paginated<T> {
   109→        pub fn new(data: Vec<T>, meta: PageMeta) -> Self {
   110→            Self { data, meta }
   111→        }
   112→    }
   113→}
