   117→//
   118→// ─────────────────────────  REDIS RESPONSE CACHE  ──────────────────────
   119→//
   120→mod cache {
   121→    use super::{ApiError, Digest, Sha256};
   122→    use redis::{aio::ConnectionManager, AsyncCommands};
   123→    use serde::{de::DeserializeOwned, Serialize};
   124→    use std::time::Duration;
   125→
   126→    #[derive(Clone)]
   127→    pub struct ResponseCache {
   128→        conn: ConnectionManager,
   129→        ttl: Duration,
   130→    }
   131→
   132→    impl ResponseCache {
   133→        pub fn new(conn: ConnectionManager, ttl: Duration) -> Self {
   134→            Self { conn, ttl }
   135→        }
   136→
   137→        /// Hashes the *logical* cache key into a deterministic 64-char SHA-256
   138→        /// hexadecimal string that is safe for Redis.
   139→        fn hash_key(key: &str) -> String {
   140→            let mut hasher = Sha256::new();
   141→            hasher.update(key.as_bytes());
   142→            format!("{:x}", hasher.finalize())
   143→        }
   144→
   145→        /// Fetches the cached value if present or, otherwise, executes the
   146→        /// async supplier closure, stores, and returns its result.
   147→        pub async fn get_or_insert_with<T, F, Fut>(
   148→            &mut self,
   149→            raw_key: &str,
   150→            supplier: F,
   151→        ) -> Result<T, ApiError>
   152→        where
   153→            T: Serialize + DeserializeOwned + Send + Sync,
   154→            F: FnOnce() -> Fut + Send,
   155→            Fut: std::future::Future<Output = Result<T, ApiError>> + Send,
   156→        {
   157→            let key = Self::hash_key(raw_key);
   158→
   159→            // 1) Try get
   160→            if let Ok(Some(buf)) = self.conn.get::<_, Vec<u8>>(&key).await {
   161→                // Do not treat JSON parsing errors as fatal – just invalidate that entry
   162→                if let Ok(value) = serde_json::from_slice::<T>(&buf) {
   163→                    return Ok(value);
   164→                } else {
   165→                    let _: Result<(), _> = self.conn.del(&key).await;
   166→                }
   167→            }
   168→
   169→            // 2) Miss: compute
   170→            let value = supplier().await?;
   171→
   172→            // 3) Store
   173→            let buf = serde_json::to_vec(&value).map_err(|e| ApiError::Cache(e.to_string()))?;
   174→            let _: () = self
   175→                .conn
   176→                .set_ex(&key, buf, self.ttl.as_secs() as usize)
   177→                .await
   178→                .map_err(|e| ApiError::Cache(e.to_string()))?;
   179→
   180→            Ok(value)
   181→        }
   182→
   183→        /// Helper to eagerly invalidate a known key (e.g. after a mutation).
   184→        pub async fn purge(&mut self, raw_key: &str) -> Result<(), ApiError> {
   185→            let key = Self::hash_key(raw_key);
   186→            self.conn
   187→                .del(&key)
   188→                .await
   189→                .map_err(|e| ApiError::Cache(e.to_string()))
   190→        }
   191→    }
   192→}
