   137→}
   138→
   139→impl RedisCache {
   140→    pub fn new(client: redis::Client) -> Self {
   141→        Self { client }
   142→    }
   143→
   144→    async fn get<T>(&self, key: &str) -> Result<Option<T>, redis::RedisError>
   145→    where
   146→        T: for<'de> Deserialize<'de>,
   147→    {
   148→        let mut conn = self.client.get_async_connection().await?;
   149→        let value: Option<String> = redis::cmd("GET").arg(key).query_async(&mut conn).await?;
   150→        match value {
   151→            Some(raw) => Ok(Some(serde_json::from_str(&raw)?)),
   152→            None => Ok(None),
   153→        }
   154→    }
   155→
   156→    async fn set<T>(&self, key: &str, value: &T, ttl_secs: usize) -> Result<(), redis::RedisError>
   157→    where
   158→        T: Serialize,
   159→    {
   160→        let payload = serde_json::to_string(value)?;
   161→        let mut conn = self.client.get_async_connection().await?;
   162→        Cmd::set_ex(key, payload, ttl_secs).query_async(&mut conn).await
   163→    }
   164→}
