   166→/// Query service – orchestrates validation, caching and repository access.
   167→#[derive(Clone)]
   168→pub struct AccountSnapshotQueryService<R: AccountSnapshotRepository> {
   169→    repo: Arc<R>,
   170→    cache: RedisCache,
   171→}
   172→
   173→impl<R: AccountSnapshotRepository> AccountSnapshotQueryService<R> {
   174→    pub fn new(repo: Arc<R>, cache: RedisCache) -> Self {
   175→        Self { repo, cache }
   176→    }
   177→
   178→    /// Composite cache-key: `snapshot:<account_id>:<YYYY-MM-DD>`
   179→    fn cache_key(account_id: uuid::Uuid, as_of: DateTime<Utc>) -> String {
   180→        format!("snapshot:{}:{}", account_id, as_of.date_naive())
   181→    }
   182→
   183→    /// Input validation before hitting cache / db
   184→    fn validate_input(
   185→        account_id: &uuid::Uuid,
   186→        as_of: &DateTime<Utc>,
   187→    ) -> Result<(), SnapshotServiceError> {
   188→        // Example rule: we only allow snapshots for past / present, no future
   189→        if *as_of > Utc::now() {
   190→            return Err(SnapshotServiceError::Validation(
   191→                "cannot request future snapshots".into(),
   192→            ));
   193→        }
   194→        Ok(())
   195→    }
   196→
   197→    /// Public async API consumed by controllers
   198→    #[instrument(skip(self))]
   199→    pub async fn get_snapshot(
   200→        &self,
   201→        account_id: uuid::Uuid,
   202→        as_of: DateTime<Utc>,
   203→    ) -> Result<AccountSnapshotVM, SnapshotServiceError> {
   204→        Self::validate_input(&account_id, &as_of)?;
   205→
   206→        let key = Self::cache_key(account_id, as_of);
   207→        // 1. Attempt cache
   208→        if let Some(vm) = self.cache.get::<AccountSnapshotVM>(&key).await? {
   209→            debug!(%account_id, %as_of, "cache-hit");
   210→            return Ok(vm);
   211→        }
   212→        debug!(%account_id, %as_of, "cache-miss");
   213→
   214→        // 2. Fetch from DB via repository
   215→        let snap = self
   216→            .repo
   217→            .fetch_snapshot(account_id, as_of)
   218→            .await?
   219→            .ok_or(SnapshotServiceError::NotFound)?;
   220→
   221→        // 3. Map to output DTO / VM
   222→        let vm: AccountSnapshotVM = snap.into();
   223→
   224→        // 4. Write-through cache (ignore errors, log only)
   225→        if let Err(err) = self
   226→            .cache
   227→            .set(&key, &vm, SNAPSHOT_CACHE_TTL_SECS)
   228→            .await
   229→        {
   230→            warn!(error=%err, %key, "failed to write snapshot to cache");
   231→        }
   232→
   233→        Ok(vm)
   234→    }
   235→}
