     2→//! src/module_55.rs
     3→//!
     4→//! Ledger Entry querying & pagination (Read side).
     5→//!
     6→//! This module represents the “Query” slice of the CQS-oriented service layer for
     7→//! Ledger Entries. It exposes:
     8→//!   • Validated request DTOs (aka *View-Models*).
     9→//!   • Domain models.
    10→//!   • A Repository abstraction + Postgres implementation.
    11→//!   • A Redis-backed response cache.
    12→//!   • A high-level `LedgerEntryQueryService` consumed by REST/GraphQL resolvers.
    13→//!
    14→//! The code purposefully avoids framework glue (Axum, Actix, async-graphql, etc.)
    15→//! so it can be compiled & tested in isolation.
    16→//!
    17→//! NOTE: This file is named `.txt` in the prompt, but should be renamed
    18→//!       to `module_55.rs` (or similar) inside `src/` in a real project.
    19→
    20→#![allow(clippy::missing_errors_doc)]
    21→
    22→use std::sync::Arc;
    23→use std::time::Duration;
    24→
    25→use async_trait::async_trait;
    26→use chrono::{DateTime, NaiveDate, Utc};
    27→use itertools::Itertools;
    28→use serde::{Deserialize, Serialize};
    29→use sha2::{Digest, Sha256};
    30→use sqlx::{postgres::PgPoolOptions, Pool, Postgres, Row};
    31→use thiserror::Error;
    32→use uuid::Uuid;
    33→use validator::{Validate, ValidationError};
    34→
    35→/// TTL applied to cached query responses.
    36→const CACHE_TTL: Duration = Duration::from_secs(30); // 30 s – conservative by default
    37→
    38→/* ---------------------------------------------------------------- *\
    39→ * Domain Model
    40→\* ---------------------------------------------------------------- */
    41→
    42→/// Single entry posted to the general ledger.
    43→#[derive(Debug, Clone, Serialize, Deserialize)]
    44→pub struct LedgerEntry {
    45→    pub id: Uuid,
    46→    pub tenant_id: Uuid,
    47→    pub booked_date: NaiveDate,
    48→    pub account_code: String,
    49→    pub currency: String,
    50→    pub debit: f64,
    51→    pub credit: f64,
    52→    pub narrative: String,
    53→    pub created_at: DateTime<Utc>,
    54→    pub updated_at: DateTime<Utc>,
    55→}
    56→
    57→/* ---------------------------------------------------------------- *\
    58→ * View-Models & Validation
    59→\* ---------------------------------------------------------------- */
    60→
    61→/// Validate that booked_from <= booked_to when both are provided.
    62→fn validate_date_range(dto: &LedgerEntryFilter) -> Result<(), ValidationError> {
    63→    if let (Some(from), Some(to)) = (dto.booked_from, dto.booked_to) {
    64→        if from > to {
    65→            return Err(ValidationError::new("invalid_date_range"));
    66→        }
    67→    }
    68→    Ok(())
    69→}
    70→
    71→/// Query filter parameters accepted by API/GraphQL callers.
    72→#[derive(Debug, Default, Clone, Deserialize, Serialize, Validate)]
    73→pub struct LedgerEntryFilter {
    74→    /// Multi-tenant isolation (required at API gateway, re-validated here).
    75→    #[validate]
    76→    pub tenant_id: Uuid,
    77→
    78→    /// Optional range filtering.
    79→    #[serde(default)]
    80→    #[validate(custom = "validate_date_range")]
    81→    pub booked_from: Option<NaiveDate>,
    82→
    83→    #[serde(default)]
    84→    pub booked_to: Option<NaiveDate>,
    85→
    86→    /// Optional account code prefix search (e.g. “4000”).
    87→    #[serde(default)]
    88→    #[validate(length(min = 1, max = 20))]
    89→    pub account_prefix: Option<String>,
    90→}
    91→
    92→/// Standardised pagination envelope.
    93→#[derive(Debug, Clone, Deserialize, Serialize, Validate)]
    94→pub struct Pagination {
    95→    /// 1-based page index.
    96→    #[validate(range(min = 1, max = 10_000))]
    97→    pub page: u32,
    98→
    99→    /// Page size.
