   122→/* ---------------------------------------------------------------- *\
   123→ * Error Handling
   124→\* ---------------------------------------------------------------- */
   125→
   126→#[derive(Debug, Error)]
   127→pub enum LedgerError {
   128→    #[error("validation error: {0}")]
   129→    Validation(#[from] validator::ValidationErrors),
   130→
   131→    #[error("repository error: {0}")]
   132→    Repository(String),
   133→
   134→    #[error("serialization error: {0}")]
   135→    Serialization(#[from] serde_json::Error),
   136→
   137→    #[error("database error: {0}")]
   138→    Database(#[from] sqlx::Error),
   139→
   140→    #[error("cache error: {0}")]
   141→    Cache(String),
   142→}
   143→
   144→impl LedgerError {
   145→    fn repository<E: std::fmt::Display>(e: E) -> Self {
   146→        Self::Repository(e.to_string())
   147→    }
   148→
   149→    fn cache<E: std::fmt::Display>(e: E) -> Self {
   150→        Self::Cache(e.to_string())
   151→    }
   152→}
