   154→/* ---------------------------------------------------------------- *\
   155→ * Repository Layer
   156→\* ---------------------------------------------------------------- */
   157→
   158→#[async_trait]
   159→pub trait LedgerEntryRepository: Send + Sync {
   160→    async fn fetch_entries(
   161→        &self,
   162→        filter: &LedgerEntryFilter,
   163→        pagination: &Pagination,
   164→    ) -> Result<(Vec<LedgerEntry>, u64), LedgerError>;
   165→}
   166→
   167→/// Postgres-backed repository.
   168→pub struct PostgresLedgerEntryRepository {
   169→    pool: Pool<Postgres>,
   170→}
   171→
   172→impl PostgresLedgerEntryRepository {
   173→    pub fn new(pool: Pool<Postgres>) -> Self {
   174→        Self { pool }
   175→    }
   176→}
   177→
   178→#[async_trait]
   179→impl LedgerEntryRepository for PostgresLedgerEntryRepository {
   180→    async fn fetch_entries(
   181→        &self,
   182→        filter: &LedgerEntryFilter,
   183→        pagination: &Pagination,
   184→    ) -> Result<(Vec<LedgerEntry>, u64), LedgerError> {
   185→        let mut conditions = vec!["tenant_id = $1".to_string()];
   186→        let mut binds: Vec<Box<dyn sqlx::Encode<'_, Postgres> + Send + Sync + 'static>> =
   187→            vec![Box::new(filter.tenant_id)];
   188→
   189→        if let Some(from) = filter.booked_from {
   190→            conditions.push(format!("booked_date >= ${}", binds.len() + 1));
   191→            binds.push(Box::new(from));
   192→        }
   193→        if let Some(to) = filter.booked_to {
   194→            conditions.push(format!("booked_date <= ${}", binds.len() + 1));
   195→            binds.push(Box::new(to));
   196→        }
   197→        if let Some(ref prefix) = filter.account_prefix {
   198→            conditions.push(format!("account_code LIKE ${}", binds.len() + 1));
   199→            binds.push(Box::new(format!("{}%", prefix)));
   200→        }
   201→
   202→        let where_clause = conditions.iter().join(" AND ");
   203→
   204→        // total count
   205→        let count_query = format!("SELECT COUNT(*) FROM ledger_entries WHERE {}", where_clause);
   206→        let total: i64 = sqlx::query_scalar_with(&count_query, binds.iter().map(|b| &**b))
   207→            .fetch_one(&self.pool)
   208→            .await
   209→            .map_err(LedgerError::Database)?;
   210→
   211→        // data query
   212→        let offset = (pagination.page - 1) * pagination.per_page;
   213→        let mut data_query = format!(
   214→            "SELECT * FROM ledger_entries WHERE {} ORDER BY booked_date DESC, id DESC LIMIT {} OFFSET {}",
   215→            where_clause, pagination.per_page, offset
   216→        );
   217→        // We cannot use binds for LIMIT/OFFSET easily with sqlx::query! macro; safe as numbers.
   218→
   219→        let rows = sqlx::query(&data_query)
   220→            .bind_all(binds) // extension, see below
   221→            .fetch_all(&self.pool)
   222→            .await
   223→            .map_err(LedgerError::Database)?;
   224→
   225→        let entries = rows
   226→            .into_iter()
   227→            .map(|row| LedgerEntry {
   228→                id: row.get("id"),
   229→                tenant_id: row.get("tenant_id"),
   230→                booked_date: row.get("booked_date"),
   231→                account_code: row.get("account_code"),
   232→                currency: row.get("currency"),
   233→                debit: row.get("debit"),
   234→                credit: row.get("credit"),
   235→                narrative: row.get("narrative"),
   236→                created_at: row.get("created_at"),
   237→                updated_at: row.get("updated_at"),
   238→            })
   239→            .collect();
   240→
   241→        Ok((entries, total as u64))
   242→    }
   243→}
