   245→/* ---------------------------------------------------------------- *\
   246→ * Caching
   247→\* ---------------------------------------------------------------- */
   248→
   249→/// A very small subset of the redis crate API to keep the snippet’s dependency
   250→/// tree lean. In production, replace with `redis::aio::ConnectionLike` et al.
   251→#[async_trait]
   252→pub trait Cache: Send + Sync {
   253→    async fn get_bytes(&self, key: &str) -> Result<Option<Vec<u8>>, LedgerError>;
   254→    async fn set_bytes(&self, key: &str, value: &[u8], ttl: Duration) -> Result<(), LedgerError>;
   255→}
   256→
   257→/// Redis implementation.
   258→pub struct RedisCache {
   259→    client: redis::Client,
   260→}
   261→
   262→impl RedisCache {
   263→    pub fn new(connection_string: &str) -> Result<Self, LedgerError> {
   264→        let client =
   265→            redis::Client::open(connection_string).map_err(|e| LedgerError::cache(e.to_string()))?;
   266→        Ok(Self { client })
   267→    }
   268→
   269→    async fn conn(&self) -> Result<redis::aio::Connection, LedgerError> {
   270→        self.client
   271→            .get_async_connection()
   272→            .await
   273→            .map_err(|e| LedgerError::cache(e.to_string()))
   274→    }
   275→}
   276→
   277→#[async_trait]
   278→impl Cache for RedisCache {
   279→    async fn get_bytes(&self, key: &str) -> Result<Option<Vec<u8>>, LedgerError> {
   280→        let mut conn = self.conn().await?;
   281→        let bytes: Option<Vec<u8>> =
   282→            redis::cmd("GET").arg(key).query_async(&mut conn).await.map_err(|e| LedgerError::cache(e.to_string()))?;
   283→        Ok(bytes)
   284→    }
   285→
   286→    async fn set_bytes(&self, key: &str, value: &[u8], ttl: Duration) -> Result<(), LedgerError> {
   287→        let mut conn = self.conn().await?;
   288→        redis::cmd("SET")
   289→            .arg(key)
   290→            .arg(value)
   291→            .arg("PX")
   292→            .arg(ttl.as_millis() as u64)
   293→            .query_async(&mut conn)
   294→            .await
   295→            .map_err(|e| LedgerError::cache(e.to_string()))?;
   296→        Ok(())
   297→    }
   298→}
