   300→/* ---------------------------------------------------------------- *\
   301→ * Service Layer
   302→\* ---------------------------------------------------------------- */
   303→
   304→#[derive(Clone)]
   305→pub struct LedgerEntryQueryService<R: LedgerEntryRepository, C: Cache> {
   306→    repository: Arc<R>,
   307→    cache: Arc<C>,
   308→}
   309→
   310→impl<R: LedgerEntryRepository, C: Cache> LedgerEntryQueryService<R, C> {
   311→    pub fn new(repository: Arc<R>, cache: Arc<C>) -> Self {
   312→        Self { repository, cache }
   313→    }
   314→
   315→    /// High-level query function to be consumed by HTTP/GraphQL handlers.
   316→    pub async fn list_entries(
   317→        &self,
   318→        filter: LedgerEntryFilter,
   319→        pagination: Pagination,
   320→    ) -> Result<LedgerEntryPage, LedgerError> {
   321→        // Step 1: validate user input
   322→        filter.validate()?;
   323→        pagination.validate()?;
   324→
   325→        // Step 2: cache lookup
   326→        let cache_key = Self::make_cache_key(&filter, &pagination);
   327→        if let Some(bytes) = self.cache.get_bytes(&cache_key).await? {
   328→            let page: LedgerEntryPage = serde_json::from_slice(&bytes)?;
   329→            return Ok(page);
   330→        }
   331→
   332→        // Step 3: fetch from repository
   333→        let (items, total_items) = self.repository.fetch_entries(&filter, &pagination).await?;
   334→        let total_pages = ((total_items as f64) / (pagination.per_page as f64)).ceil() as u32;
   335→
   336→        let page = LedgerEntryPage {
   337→            items,
   338→            total_items,
   339→            total_pages,
   340→            page: pagination.page,
   341→            per_page: pagination.per_page,
   342→            cache_ttl_secs: CACHE_TTL.as_secs(),
   343→        };
   344→
   345→        // Step 4: store in cache (best-effort)
   346→        if let Ok(bytes) = serde_json::to_vec(&page) {
   347→            let _ = self
   348→                .cache
   349→                .set_bytes(&cache_key, &bytes, CACHE_TTL)
   350→                .await;
