    30→use validator::{Validate, ValidationError};
    31→
    32→/// The maximum amount of elements that can be retrieved in a single page.
    33→/// Going beyond this hurts DB & network throughput and opens the door for
    34→/// DoS attacks.
    35→const MAX_LIMIT: u32 = 250;
    36→
    37→/// How long a paginated list is allowed to live inside our CDN / Redis (secs).
    38→/// Ledger data does not change *that* often (writes are append-only) so we can
    39→/// afford a reasonably aggressive cache.
    40→const DEFAULT_TTL_SECONDS: u64 = 10;
    41→
    42→/// A strongly-typed representation of client-supplied paging parameters.
    43→#[derive(Debug, Clone, Serialize, Deserialize, Validate)]
    44→pub struct Pagination {
    45→    /// Number of records to skip (SQL `OFFSET`)
    46→    #[validate(custom = "validate_offset")]
    47→    pub offset: u32,
    48→    /// Number of records to fetch (SQL `LIMIT`)
    49→    #[validate(custom = "validate_limit")]
    50→    pub limit:  u32,
    51→    /// Optional column(s) used for sorting (e.g. `"created_at:desc"`).
    52→    pub sort:   Option<String>,
    53→}
    54→
    55→impl Default for Pagination {
    56→    fn default() -> Self {
    57→        Self {
    58→            offset: 0,
    59→            limit:  50,
    60→            sort:   None,
    61→        }
    62→    }
    63→}
    64→
    65→/// Custom offset validator — negative values are already impossible (u32),
    66→/// but we still disallow **gigantic** values to protect the DB.
    67→fn validate_offset(offset: &u32) -> Result<(), ValidationError> {
    68→    if *offset > 100_000 {
    69→        return Err(ValidationError::new("offset_too_large"));
    70→    }
    71→    Ok(())
    72→}
    73→
    74→/// Custom limit validator — cannot exceed `MAX_LIMIT`.
    75→fn validate_limit(limit: &u32) -> Result<(), ValidationError> {
    76→    if *limit == 0 || *limit > MAX_LIMIT {
    77→        return Err(ValidationError::new("limit_out_of_bounds"));
    78→    }
    79→    Ok(())
    80→}
    81→
    82→impl Pagination {
    83→    /// Tries to build a [`Pagination`] struct from an arbitrary query map,
    84→    /// returning validation errors early.
    85→    pub fn try_from_query_map(
    86→        params: &HashMap<String, String>,
    87→    ) -> Result<Self, PaginationError> {
    88→        let offset = params
    89→            .get("offset")
    90→            .and_then(|v| v.parse::<u32>().ok())
    91→            .unwrap_or_default();
    92→
    93→        let limit = params
    94→            .get("limit")
    95→            .and_then(|v| v.parse::<u32>().ok())
    96→            .unwrap_or_else(|| Self::default().limit);
    97→
    98→        let sort = params.get("sort").cloned();
    99→
   100→        let candidate = Self { offset, limit, sort };
   101→
   102→        candidate.validate()?;
   103→
   104→        Ok(candidate)
   105→    }
   106→
   107→    /// Calculates SQL LIMIT/OFFSET for the current page.
   108→    #[must_use]
   109→    pub fn sql_limit_offset(&self) -> (u32, u32) {
   110→        (self.limit, self.offset)
   111→    }
   112→}
   113→
   114→/// The envelope returned by list-style endpoints.
   115→#[derive(Debug, Clone, Serialize)]
   116→pub struct Paginated<T>
   117→where
   118→    T: Serialize,
   119→{
   120→    pub items:       Vec<T>,
   121→    pub total:       u64,
   122→    pub offset:      u32,
   123→    pub limit:       u32,
   124→    pub has_more:    bool,
   125→    #[serde(skip_serializing_if = "Option::is_none")]
   126→    pub cache_hint:  Option<CacheHint>,
   127→}
   128→
   129→impl<T> Paginated<T>
   130→where
   131→    T: Serialize,
   132→{
   133→    pub fn new(
   134→        items: Vec<T>,
   135→        total: u64,
   136→        pagination: &Pagination,
   137→        cacheable: bool,
